use prompty::model::RetryPayload;
use prompty::model::context::{LoadContext, SaveContext};

#[test]
fn test_retry_payload_load_json() {
    let json = r####"
{
  "operation": "llm",
  "attempt": 2,
  "maxAttempts": 3,
  "delayMs": 1250,
  "reason": "rate_limit"
}
"####;
    let ctx = LoadContext::default();
    let result = RetryPayload::from_json(json, &ctx);
    assert!(result.is_ok(), "Failed to load from JSON: {:?}", result.err());
    let instance = result.unwrap();
    assert_eq!(instance.operation, "llm");
    assert_eq!(instance.attempt, 2);
    assert!(instance.max_attempts.is_some(), "Expected max_attempts to be Some");
    assert_eq!(instance.max_attempts.as_ref().unwrap(), &3);
    assert!(instance.delay_ms.is_some(), "Expected delay_ms to be Some");
    assert_eq!(instance.delay_ms.as_ref().unwrap(), &1250.0);
    assert!(instance.reason.is_some(), "Expected reason to be Some");
    assert_eq!(instance.reason.as_ref().unwrap(), &"rate_limit");
}

